// Node 4 – Termin extrahieren (roher Notion-Response, simple=false).
const page  = $input.first().json;
const props = page.properties || {};

function relationIds(prop) {
  if (!prop) return [];
  if (Array.isArray(prop.relation)) return prop.relation.map(r => (r && r.id) || r).filter(Boolean);
  if (Array.isArray(prop))          return prop.map(r => (r && r.id) || r).filter(Boolean);
  return [];
}
function findProp(props, regex) {
  if (props[regex.source]) return props[regex.source];
  const key = Object.keys(props).find(k => regex.test(k));
  return key ? props[key] : null;
}

function getText(prop) {
  if (!prop) return '';
  if (prop.type === 'rich_text') return (prop.rich_text || []).map(r => r.plain_text).join('');
  if (prop.type === 'title')     return (prop.title || []).map(r => r.plain_text).join('');
  if (prop.type === 'url')       return prop.url || '';
  if (prop.type === 'email')     return prop.email || '';
  if (prop.type === 'checkbox')  return !!prop.checkbox;
  if (prop.type === 'select')    return prop.select?.name || '';
  return '';
}
function formatTermin(dateObj) {
  if (!dateObj?.start) return '';
  const start = new Date(dateObj.start);
  const dateStr   = start.toLocaleDateString('de-DE', { day:'2-digit', month:'2-digit', year:'numeric' });
  const startTime = start.toLocaleTimeString('de-DE', { hour:'2-digit', minute:'2-digit', hour12:false });
  if (dateObj.end) {
    const end = new Date(dateObj.end);
    const endTime = end.toLocaleTimeString('de-DE', { hour:'2-digit', minute:'2-digit', hour12:false });
    return `${dateStr}, ${startTime} – ${endTime} Uhr`;
  }
  return `${dateStr}, ${startTime} Uhr`;
}

function parseTermine(raw) {
  if (!raw) return [];
  return raw.split('\n').map(l => l.trim()).filter(Boolean).map((line) => {
    const [datum, ort] = line.split('|').map(s => s.trim());
    return { termin_datum: datum, termin_ort_oder_leer: ort || '______________________' };
  });
}

const datumProp  = props['Datum']?.date;
const dateiDatum = datumProp?.start ? new Date(datumProp.start).toISOString().slice(0,10) : 'unbekannt';

// DB Gruppen Relation -> erste Gruppen-Page-ID (tolerant; leer => IF-Node fängt es ab)
const gruppenId = relationIds(findProp(props, /db\s*gruppe|gruppe|board/i))[0] || null;

return [{
  json: {
    page_id:          page.id,
    gruppen_id:       gruppenId,
    termin:           formatTermin(datumProp),
    datei_datum:      dateiDatum,
    ort_name:         getText(props['Ort Name']),
    ort_adresse:      getText(props['Ort Adresse']),
    gast_name:        getText(props['Gast Name']),
    gast_web:         getText(props['Gast Web']),
    gastvortrag_name: getText(props['Gastvortrag-Name']),
    gastvortrag_web:  getText(props['Gastvortrag Web']),
    hotseat1_name:    getText(props['Hotseat1-Name']),
    hotseat1_thema:   getText(props['Hotseat1-Thema']),
    hotseat2_name:    getText(props['Hotseat2-Name']),
    hotseat2_thema:   getText(props['Hotseat2-Thema']),
    themenvorschau:   getText(props['Themenvorschau']),
    impulsvortrag:    getText(props['Impulsvortrag']),
    naechste_termine: parseTermine(getText(props['Nächste Termine'])),
    output_path:      `/opt/scripts/output/AGD_${dateiDatum}_Boardmeeting.docx`,
  }
}];

// Node 7 – Kunden-IDs extrahieren: gibt MEHRERE Items zurück (1 pro Kunde).
// Hinweis Pagination: Notion liefert max. 25 Relations pro Page; bei größeren
// Gruppen über GET /v1/pages/{id}/properties/{prop_id} nachladen.
const gruppePage = $input.first().json;
const props = gruppePage.properties || {};

function relationIds(prop) {
  if (!prop) return [];
  if (Array.isArray(prop.relation)) return prop.relation.map(r => (r && r.id) || r).filter(Boolean);
  if (Array.isArray(prop))          return prop.map(r => (r && r.id) || r).filter(Boolean);
  return [];
}
function findProp(props, regex) {
  if (props[regex.source]) return props[regex.source];
  const key = Object.keys(props).find(k => regex.test(k));
  return key ? props[key] : null;
}

const kundenIds = relationIds(findProp(props, /db\s*kunde|kunde|mitglied/i));
const terminDaten = $('Code: Termin extrahieren').first().json;
// NEU:
const gruppenName = 
  // Erst Title-Feld versuchen
  gruppePage.properties?.['Name']?.title?.map(r => r.plain_text).join('') ||
  // Dann Confluence Space Key als Fallback
  gruppePage.properties?.['Confluence Space Key']?.rich_text?.map(r => r.plain_text).join('') ||
  // Letzter Fallback
  'Unbekannte Gruppe';

if (kundenIds.length === 0) {
  return [{ json: { ...terminDaten, kunden_id: null, alle_kunden_ids: [], gruppen_name: gruppenName } }];
}

return kundenIds.map(id => ({
  json: {
    ...terminDaten,
    kunden_id: id,
    alle_kunden_ids: kundenIds,
    gruppen_name: gruppenName,
  }
}));

// Node 9 – Payload aufbereiten
const alleItems = $input.all();

function getText(prop) {
  if (!prop) return '';
  if (prop.type === 'rich_text') return (prop.rich_text || []).map(r => r.plain_text).join('');
  if (prop.type === 'title')     return (prop.title || []).map(r => r.plain_text).join('');
  if (prop.type === 'url')       return prop.url || '';
  if (prop.type === 'email')     return prop.email || '';
  if (prop.type === 'checkbox')  return !!prop.checkbox;
  if (prop.type === 'select')    return prop.select?.name || '';
  return '';
}

// Mitglieder aufbereiten
const mitglieder = alleItems
  .map(item => item.json.properties)
  .filter(Boolean)
  .map(props => ({
    name:  getText(props['Name']),
    firma: getText(props['Firma']),
    web:   getText(props['Web']),
    aktiv: getText(props['Aktiv']),
  }))
  .filter(m => m.name && m.aktiv !== false)
  .map(({ name, firma, web }, index) => ({
    name, firma, web,
    ist_erstes: index === 0,
  }));

// Termin-Daten und Gruppenname
const data = $('Code: Termin extrahieren').first().json;
// NEU:
// gruppen_name steckt in den Items vom HTTP: Kunden laden Node
// dort wurde es via ...terminDaten weitergegeben
const gruppenName = $input.all()
  .map(i => i.json.gruppen_name)
  .find(n => n && n !== 'Unbekannte Gruppe') || 
  $('Code: Kunden-IDs extrahieren').first().json.gruppen_name ||
  'Unbekannte_Gruppe';
const dateiName = `AGD_${data.datei_datum}_${gruppenName.replace(/\s+/g, '_')}_Boardmeeting.docx`;

// TOPs aufbauen
const tops = [];

tops.push({ titel: 'Begrüßung & Agenda', zeit: '10min', beschreibung: '', untertitel: '', sub_items: [] });

if (data.gastvortrag_name) {
  tops.push({ titel: 'Impulsvortrag', zeit: '', beschreibung: data.impulsvortrag || '', untertitel: '', sub_items: [] });
}

if (data.hotseat1_name || data.hotseat2_name) {
  const subItems = [];
  if (data.hotseat1_name) subItems.push({ nr: 1, fallgeber: data.hotseat1_name, sub_zeit: '20min', sub_beschreibung: data.hotseat1_thema || '' });
  if (data.hotseat2_name) subItems.push({ nr: 2, fallgeber: data.hotseat2_name, sub_zeit: '20min', sub_beschreibung: data.hotseat2_thema || '' });
  tops.push({ titel: 'Vorstellung neue Themen', zeit: '', beschreibung: '', untertitel: 'was ist geplant, was soll umgesetzt werden, wo wird Hilfe benötigt', sub_items: subItems });
}

tops.push({ titel: 'Aktuelle Themen / Offene Fragen', zeit: '30min', beschreibung: '', untertitel: '', sub_items: [] });
tops.push({ titel: 'Themen Vorschau nächste Sitzung', zeit: '', beschreibung: data.themenvorschau || '', untertitel: '', sub_items: [] });

const payload = {
  termin:           data.termin,
  ort_name:         data.ort_name,
  ort_adresse:      data.ort_adresse,
  mitglieder,
  gast_name:        data.gast_name,
  gast_web:         data.gast_web,
  gastvortrag_name: data.gastvortrag_name,
  gastvortrag_web:  data.gastvortrag_web,
  tops,
  themenvorschau:   '',
  naechste_termine: data.naechste_termine || [],
};

return [{
  json: {
    page_id:        data.page_id,
    datei_datum:    data.datei_datum,
    gruppen_name:   gruppenName,
    datei_name:     dateiName,
    output_path:    `/root/local-files/${dateiName}`,
    container_path: `/files/${dateiName}`,
    agenda_datum:   new Date().toISOString().slice(0, 10),
    payload,
  }
}];

// Base64 vom Agenda-Server in Binary umwandeln
const base64 = $('HTTP: Agenda erzeugen').first().json.file_base64;
const filename = $('HTTP: Agenda erzeugen').first().json.filename;

// gruppen_name aus dem Input lesen (kommt vom vorherigen Node)
const gruppen_name = $input.first().json.gruppen_name || 'Unbekannte_Gruppe';
const datei_datum = $input.first().json.datei_datum || '';
const termin = $input.first().json.termin || '';
const page_id = $input.first().json.page_id || '';

const binary = {
  attachment: {
    data: base64,
    mimeType: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
    fileName: filename,
  }
};

return [{
  json: {
    gruppen_name,
    datei_datum,
    termin,
    page_id,
  },
  binary
}];
